import { useState, useCallback, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import PageTransition from "@/components/PageTransition";
import FocusGame from "@/components/games/FocusGame";
import TargetTracker from "@/components/games/TargetTracker";
import MemoryGame from "@/components/games/MemoryGame";
import DistractionGame from "@/components/games/DistractionGame";
import NeuralPath from "@/components/games/NeuralPath";
import { useGameStore, GameResult } from "@/store/useGameStore";
import { ArrowLeft, Scan, Circle, Brain, Palette, Workflow } from "lucide-react";
import { toast } from "sonner";

const ALL_GAMES = [
  { key: "focus", label: "Focus Finder", icon: Scan },
  { key: "reaction", label: "Find the Ball", icon: Circle },
  { key: "memory", label: "Match Master", icon: Brain },
  { key: "distraction", label: "Color Clash", icon: Palette },
  { key: "impulse", label: "Neural Path", icon: Workflow },
];

export default function Games() {
  const location = useLocation();
  const navigate = useNavigate();
  const { gameId } = useParams();

  const activeSessionId = useGameStore(state => state.activeSessionId);
  const addGameResult = useGameStore(state => state.addGameResult);
  const createSession = useGameStore(state => state.createSession);

  // Auto-initialize session if none exists! ≡ƒ¢í∩╕ÅΓ£¿
  useEffect(() => {
    if (!activeSessionId) {
      createSession();
    }
  }, [activeSessionId, createSession]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const sessionId = (location.state as any)?.sessionId || activeSessionId;
  const routeStateGame = (location.state as any)?.singleGame as string | undefined;

  const singleGame = gameId || routeStateGame;

  // If single game mode, only play that one
  const GAMES = singleGame
    ? ALL_GAMES.filter(g => g.key === singleGame)
    : ALL_GAMES;

  const [currentGame, setCurrentGame] = useState(0);
  const [transitioning, setTransitioning] = useState(false);
  const [results, setResults] = useState<GameResult[]>([]);

  // High Score popup logic
  const checkHighScore = useCallback((gameType: string, newScore: number) => {
    const allSessions = useGameStore.getState().sessions;
    if (allSessions.length === 0) return;

    // Find highest previous score for this gameType
    let bestPrev = 0;
    allSessions.forEach(session => {
      const match = session.results.find(r => r.gameType === gameType);
      if (match && match.score > bestPrev) {
        bestPrev = match.score;
      }
    });

    if (newScore > bestPrev && bestPrev > 0) {
      toast.success("New High Score!", {
        description: `You beat your previous best of ${bestPrev} in ${gameType}! ≡ƒÄë`,
        duration: 4000,
      });
    }
  }, []);

  const handleGameComplete = useCallback((result: GameResult) => {
    checkHighScore(result.gameType, result.score);
    if (sessionId) addGameResult(result);
    const newResults = [...results, result];
    setResults(newResults);

    setTransitioning(true);
    setTimeout(() => {
      if (currentGame < GAMES.length - 1) {
        setCurrentGame(c => c + 1);
        setTransitioning(false);
      } else {
        navigate("/results", { state: { sessionId, results: newResults, singleGame } });
      }
    }, 2000);
  }, [currentGame, sessionId, navigate, results, GAMES.length, addGameResult, checkHighScore]);

  const getEmotionalFeedback = (score: number) => {
    if (score >= 90) return "Incredible! ≡ƒöÑ";
    if (score >= 70) return "Great job! ≡ƒÜÇ";
    if (score >= 40) return "Solid effort! ≡ƒÆ¬";
    return "Keep trying! ≡ƒºá";
  };

  const game = GAMES[currentGame];

  return (
    <PageTransition>
      <div className="flex-1 flex flex-col px-4 py-8 md:px-12 relative overflow-hidden h-full">
        {/* Back button for individual game mode */}
        {singleGame && (
          <button
            onClick={() => navigate("/games-hub")}
            className="flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors mb-4 self-start"
          >
            <ArrowLeft className="w-4 h-4" /> Back to Games
          </button>
        )}

        {/* Progress */}
        {GAMES.length > 1 && (
          <div className="flex items-center gap-2 mb-4 justify-center">
            {GAMES.map((g, i) => (
              <div key={g.key} className="flex items-center gap-1">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
                  i < currentGame ? "bg-primary text-primary-foreground" :
                  i === currentGame ? "bg-primary text-primary-foreground animate-pulse shadow-lg shadow-primary/30" :
                  "bg-muted text-muted-foreground"
                }`}>
                  {i < currentGame ? "Γ£ô" : <g.icon className="w-4 h-4" />}
                </div>
                {i < GAMES.length - 1 && (
                  <div className={`w-6 h-0.5 ${i < currentGame ? "bg-primary" : "bg-muted"}`} />
                )}
              </div>
            ))}
          </div>
        )}

        {/* Game area */}
        <div className="flex-1 relative w-full flex flex-col">
          <AnimatePresence mode="wait">
            {transitioning ? (
              <motion.div
                key="transition"
                className="flex flex-col items-center justify-center h-full gap-4 min-h-96"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
              >
                <motion.span className="text-6xl mb-2" animate={{ scale: [1, 1.3, 1], rotate: [0, 10, -10, 0] }} transition={{ duration: 0.6 }}>
                  {results[results.length - 1]?.score >= 80 ? "≡ƒöÑ" : "Γ£¿"}
                </motion.span>
                <h3 className="text-2xl font-bold text-primary">
                  {getEmotionalFeedback(results[results.length - 1]?.score || 0)}
                </h3>
                <p className="text-foreground font-medium text-lg">
                  +{Math.round((results[results.length - 1]?.score || 0) * 1.5)} Points Earned!
                </p>
                {currentGame < GAMES.length - 1 && (() => {
                  const NextIcon = GAMES[currentGame + 1].icon;
                  return (
                    <p className="text-muted-foreground text-sm flex items-center gap-2">
                      Next: {GAMES[currentGame + 1].label} <NextIcon className="w-4 h-4" />
                    </p>
                  );
                })()}
              </motion.div>
            ) : (
              <motion.div
                key={game.key}
                className="flex-1 flex flex-col relative w-full"
                initial={{ opacity: 0, x: 30 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -30 }}
              >
                {game.key === "focus"       && <FocusGame       onComplete={handleGameComplete} />}
                {game.key === "reaction"    && <TargetTracker   onComplete={handleGameComplete} />}
                {game.key === "memory"      && <MemoryGame      onComplete={handleGameComplete} />}
                {game.key === "distraction" && <DistractionGame onComplete={handleGameComplete} />}
                {game.key === "impulse" && <NeuralPath onComplete={handleGameComplete} />}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </PageTransition>
  );
}

import { useState } from "react";
