export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const { signIn, signInWithGoogle } = useGameStore();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();

    // Stricter Validation (Task 11)
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      toast.error("Invalid Email", { description: "Please enter a valid email address." });
      return;
    }
    if (password.length < 6) {
      toast.error("Weak Password", { description: "Passwords must be at least 6 characters." });
      return;
    }

    setIsLoading(true);
    try {
      await signIn(email, password);
      toast.success("Welcome back!", { description: "Synchronizing your brain data..." });
      navigate("/dashboard");
    } catch (error: any) {
      toast.error("Login Failed", { description: error.message || "Please check your credentials." });
    } finally {
      setIsLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    try {
      await signInWithGoogle();
      toast.success("Signed in with Google!");
      navigate("/dashboard");
    } catch (error: any) {
      toast.error("Google Sign-in Failed");
    }
  };

