export default function Settings() {
  const navigate = useNavigate();
  const { theme, setTheme } = useTheme();
  const { user, signOut, soundEnabled, setSoundEnabled, retrainAI, sessions, streak } = useGameStore();

  useDocumentTitle("Account Settings");

  const [name, setName] = useState(user?.name || "");
  const [saved, setSaved] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [notifications, setNotifications] = useState(true);
  const [showClearModal, setShowClearModal] = useState(false);
  const [isRetraining, setIsRetraining] = useState(false);

  // Compute Analytics Data
  const allResults = sessions?.flatMap(s => s.results) || [];
  const totalGames = allResults.length;
  const avgScore = totalGames > 0 ? Math.round(allResults.reduce((acc, r) => acc + r.score, 0) / totalGames) : 0;
  const bestScore = totalGames > 0 ? Math.max(...allResults.map(r => r.score)) : 0;

  const handleSave = () => {
    if (user) {
      const newUser = { ...user, name };
      useGameStore.setState({ user: newUser });
      updateUser({ id: user.id, name });
    }

    setSaved(true);
    setTimeout(() => {
      setSaved(false);
      setIsEditing(false);
    }, 1200);
  };

  const handleLogout = async () => {
    localStorage.removeItem("mindly-storage");
    window.location.href = "/";
  };

  const handleRetrain = async () => {
    if (sessions.filter(s => s.completed).length === 0) {
      toast.error("Play some games first to train your AI!");
      return;
    }

    setIsRetraining(true);
    const accuracy = await retrainAI();
    setIsRetraining(false);

    if (accuracy > 0) {
      toast.success(`AI Recalibrated! Brain Accuracy: ${Math.round(accuracy * 100)}%`, {
        description: "Your Mindly AI now understands your patterns even better.",
      });
    } else {
      toast.error("Recalibration failed. Try playing more games!");
    }
  };

  const handleClearData = () => {
    useGameStore.getState().hydrate({ 
      sessions: [], 
      streak: { currentStreak: 0, longestStreak: 0, lastPlayedDate: '', totalPoints: 0, weeklyPoints: 0, weekStartDate: '' } 
    });
    if (user?.id) {
       updateUser({ 
         id: user.id, 
